}
function buildDocumentsBlock(atts, opts) {
  if (!Array.isArray(atts) || atts.length === 0) return '';
  const o = opts || {};
  const perDoc = Number.isFinite(o.maxCharsPerDoc) && o.maxCharsPerDoc > 0 ? o.maxCharsPerDoc : 6000;
  const totalCap = Number.isFinite(o.maxTotalChars) && o.maxTotalChars > 0 ? o.maxTotalChars : 24000;
  const parts = [];
