    const truncated = truncate(body, cap);
    const ref = a.ref || 'att_unknown';
    const kind = a.kind || 'document';
    const filename = a.filename || '';
    const entry = `[ref=${ref}, kind=${kind}, filename=${filename}]\n${truncated}`;
    parts.push(entry);
