  }
  if (parts.length === 0) return '';
  return `<DOCUMENTS>\n${parts.join('\n\n')}\n</DOCUMENTS>`;
}
function buildAttachmentList(atts) {
  if (!Array.isArray(atts) || atts.length === 0) return '';
  const lines = [];
  for (const a of atts) {
    if (!a || typeof a !== 'object') continue;
    const dim = a.width && a.height ? ` ${a.width}x${a.height}` : '';
    const filename = a.filename ? `, ${a.filename}` : '';
    const mime = a.mimeType ? `, mime=${a.mimeType}` : '';
    lines.push(`- [${a.ref || 'att_?'}] kind=${a.kind || 'other'}${filename}${dim}${mime}`);
    if (nonEmpty(a.description)) lines.push(`  Description: ${a.description.slice(0, 240)}`);
  }
  return lines.join('\n');
}

